/**
 * Coarse fingerprint of a vitals snapshot for repaint dedupe while only the one-line StatusBar is visible (it renders just per-state counts and fallback markers). Volatile fields are excluded (lastHeartbeatAt) or bucketed (cpu/mem to 5%, latency to health bands, stall duration to 10s) so probe jitter does not retrigger renders \u2014 an Ink repaint clears the user's terminal text selection, so an idle screen must stay byte-for-byte still. Deliberately COARSER than the /status dashboard's 1%/1ms rows: while that dashboard is open the subscriber bypasses this dedupe entirely (see startTelemetryPoller).
 */
// @kern-source: telemetry:126
export function vitalsRenderSignature(engines: EngineVitals[]): string {
  const bucket = (value: number | null | undefined, size: number): string =>
    typeof value === 'number' && Number.isFinite(value) ? String(Math.round(value / size)) : '-';
  const latencyBand = (ms: number | null | undefined): string => {
    if (typeof ms !== 'number' || !Number.isFinite(ms)) return '-';
    if (ms < 100) return 'a';
    if (ms < 300) return 'b';
    if (ms < 800) return 'c';
    if (ms < 1500) return 'd';
    return 'e';
  };
  return engines
    .slice()
    .sort((a, b) => a.engineId.localeCompare(b.engineId))
    .map((v) => [
      v.engineId,
      v.state,
      v.network ?? '-',
      v.task ?? '-',
      v.taskDetail ?? '-',
      v.fallbackTo ?? '-',
      v.fallbackReason ?? '-',
      bucket(v.cpuPercent, 5),
      bucket(v.memPercent, 5),
      latencyBand(v.latencyMs),
      bucket(v.stallDurationMs, 10000),
    ].join('|'))
    .join('\n');
}
